import { execFileSync } from 'node:child_process';
import { writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const openapiPath = join(root, 'openapi', 'openapi.json');
const outputPath = join(root, 'src', 'lib', 'api', 'types.ts');
const openapiBin = join(root, 'node_modules', '.bin', 'openapi-typescript');

const header = `/**
 * <auto-generated>
 * Generated from ui/openapi/openapi.json — do not edit by hand.
 * Run: npm run regen-api-types (after ./scripts/export_openapi.py)
 * </auto-generated>
 */
`;

const generated = execFileSync(openapiBin, [openapiPath, '--export-type'], {
	cwd: root,
	encoding: 'utf8'
});

writeFileSync(outputPath, header + generated, 'utf8');
console.log(`Wrote ${outputPath}`);
